SELECT COUNT(*)
FROM board_comment
WHERE board_seq = #{boardSeq}
  AND writer_member_seq = #{memberSeq}
  AND show_yn = 'Y'

SELECT vote_type
FROM board_comment_vote
WHERE board_comment_seq = #{boardCommentSeq}
  AND member_seq = #{memberSeq}

mapper.update:
UPDATE board_comment_vote
   SET vote_type = #{voteType}
 WHERE board_comment_seq = #{boardCommentSeq}
   AND member_seq = #{memberSeq}

UPDATE board_comment
   SET like_count = IFNULL(like_count, 0) + #{deltaLike},
       dislike_count = IFNULL(dislike_count, 0) + #{deltaDislike}
 WHERE board_comment_seq = #{boardCommentSeq}

UPDATE board_comment
   SET report_count = IFNULL(report_count, 0) + 1
 WHERE board_comment_seq = #{boardCommentSeq}

UPDATE board_comment
   SET content = #{body.content},
       emoticon_seq_1 = #{body.emoticonSeq1},
       emoticon_seq_2 = #{body.emoticonSeq2},
       emoticon_seq_3 = #{body.emoticonSeq3},
       modify_dt = NOW()
 WHERE board_comment_seq = #{boardCommentSeq}
   AND board_seq = #{boardSeq}
   AND writer_member_seq = #{writerMemberSeq}
   AND show_yn = 'Y'

UPDATE board_comment
   SET show_yn = 'N'
 WHERE board_seq = #{boardSeq}
   AND show_yn = 'Y'
   AND (board_comment_seq = #{rootCommentSeq}
        OR parent_board_comment_seq = #{rootCommentSeq})

UPDATE board_comment
   SET show_yn = 'N'
 WHERE board_seq = #{boardSeq}
   AND board_comment_seq = #{boardCommentSeq}
   AND show_yn = 'Y'

